1	/**
2	 * Filesystem scanner per WORKER_LOGIC §4.
3	 *
4	 * - Validates roots at startup (fail-fast)
5	 * - Does NOT follow symlinks
6	 * - Tracks counters for all error conditions
7	 * - Yields file candidates (.psd, .ai) with stat info
8	 *
9	 * Last reviewed: 2026-02-24
10	 */
11	
12	import { readdir, stat, lstat } from "node:fs/promises";
13	import { join, extname, basename, relative } from "node:path";
14	import { config } from "./config.js";
15	import { logger } from "./logger.js";
16	import type { Counters } from "./api-client.js";
17	import { shouldSkipFolder, shouldSkipPath, resetSkipWarnings } from "@popdam/path-filters";
18	
19	const SUPPORTED_EXTENSIONS = new Set([".psd", ".ai", ".pdf"]);
20	
21	// PDF keyword filter: only ingest PDFs whose filename matches these keywords
22	const PDF_KEYWORDS = [
23	  "tech pack", "tech_pack", "techpack", "tech-pack",
24	  "licensing sheet", "licensing-sheet", "licensing_sheet",
25	  "_comp view", "_compview",
26	];
27	
28	export function isPdfCandidate(filename: string): boolean {
29	  const lower = filename.toLowerCase();
30	  return PDF_KEYWORDS.some(kw => lower.includes(kw));
31	}
32	
33	export interface FileCandidate {
34	  absolutePath: string;
35	  relativePath: string; // POSIX canonical (no leading slash)
36	  filename: string;
37	  fileType: "psd" | "ai" | "pdf";
38	  fileSize: number;
39	  modifiedAt: Date;
40	  fileCreatedAt: Date | null;
41	}
42	
43	/**
44	 * Validate that all configured scan roots exist and are readable directories.
45	 * Per WORKER_LOGIC §4.1: refuse to scan if any root is invalid.
46	 */
47	export async function validateScanRoots(counters: Counters, scanRoots?: string[], mountRoot?: string): Promise<boolean> {
48	  const roots = scanRoots ?? config.scanRoots;
49	  const effectiveMountRoot = mountRoot || config.nasContainerMountRoot;
50	  let allValid = true;
51	
52	  for (const root of roots) {
53	    // Validate against NAS_CONTAINER_MOUNT_ROOT
54	    if (!root.startsWith(effectiveMountRoot)) {
55	      logger.error("Scan root is outside NAS_CONTAINER_MOUNT_ROOT", { root, mountRoot: effectiveMountRoot });
56	      counters.roots_invalid++;
57	      allValid = false;
58	      continue;
59	    }
60	
61	    try {
62	      const s = await stat(root);
63	      if (!s.isDirectory()) {
64	        logger.error("Scan root is not a directory", { root });
65	        counters.roots_invalid++;
66	        allValid = false;
67	      }
68	    } catch (e) {
69	      const code = (e as NodeJS.ErrnoException).code;
70	      if (code === "ENOENT") {
71	        logger.error("Scan root does not exist", { root });
72	        counters.roots_invalid++;
73	      } else if (code === "EACCES") {
74	        logger.error("Scan root is not readable", { root });
75	        counters.roots_unreadable++;
76	      } else {
77	        logger.error("Scan root stat failed", { root, error: (e as Error).message });
78	        counters.roots_invalid++;
79	      }
80	      allValid = false;
81	    }
82	  }
83	
84	  return allValid;
85	}
