1	import { useQuery } from "@tanstack/react-query";
2	import { supabase } from "@/integrations/supabase/client";
3	import type { Json } from "@/integrations/supabase/types";
4	import type { Asset, AssetFilters, SortField, SortDirection, FacetCounts } from "@/types/assets";
5	import { useAdminApi } from "@/hooks/useAdminApi";
6	
7	const PAGE_SIZE = 200;
8	
9	/** Fetch THUMBNAIL_MIN_DATE from admin_config (cached) */
10	export function useVisibilityDate() {
11	  return useQuery({
12	    queryKey: ["visibility-date"],
13	    queryFn: async () => {
14	      const { data } = await supabase
15	        .from("admin_config")
16	        .select("value")
17	        .eq("key", "THUMBNAIL_MIN_DATE")
18	        .maybeSingle();
19	      if (data?.value) {
20	        const raw = typeof data.value === "string" ? data.value : String(data.value);
21	        return raw;
22	      }
23	      return "2020-01-01";
24	    },
25	    staleTime: 5 * 60 * 1000,
26	  });
27	}
