29	function applyFilters(query: any, filters: AssetFilters) {
30	  query = query.eq("is_deleted", false);
31	
32	  if (filters.search) {
33	    query = query.ilike("filename", `%${filters.search}%`);
34	  }
35	  if (filters.fileType.length > 0) {
36	    query = query.in("file_type", filters.fileType);
37	  }
38	  if (filters.status.length > 0) {
39	    query = query.in("status", filters.status);
40	  }
41	  if (filters.workflowStatus.length > 0) {
42	    query = query.in("workflow_status", filters.workflowStatus);
43	  }
44	  if (filters.isLicensed !== null) {
45	    query = query.eq("is_licensed", filters.isLicensed);
46	  }
47	  if (filters.licensorId) {
48	    query = query.eq("licensor_id", filters.licensorId);
49	  }
50	  if (filters.propertyId) {
51	    query = query.eq("property_id", filters.propertyId);
52	  }
53	  if (filters.assetType.length > 0) {
54	    query = query.in("asset_type", filters.assetType);
55	  }
56	  if (filters.artSource.length > 0) {
57	    query = query.in("art_source", filters.artSource);
58	  }
59	  if (filters.productCategory.length > 0) {
60	    query = query.in("product_category", filters.productCategory);
61	  }
62	  if (filters.tagFilter) {
63	    query = query.contains("tags", [filters.tagFilter]);
64	  }
65	
66	  // File Status filter (supports multi-select via OR)
67	  if (filters.fileStatus.length > 0) {
68	    const orClauses: string[] = [];
69	    for (const fs of filters.fileStatus) {
70	      if (fs === "has_preview") {
71	        orClauses.push("thumbnail_url.not.is.null");
72	      } else if (fs === "no_preview_renderable") {
73	        orClauses.push("and(thumbnail_url.is.null,thumbnail_error.is.null)");
74	      } else if (fs === "no_pdf_compat") {
75	        orClauses.push("and(thumbnail_url.is.null,thumbnail_error.eq.no_pdf_compat)");
76	      } else if (fs === "no_preview_unsupported") {
77	        orClauses.push("and(thumbnail_url.is.null,thumbnail_error.eq.no_preview_or_render_failed)");
78	      }
79	    }
80	    if (orClauses.length > 0) {
81	      query = query.or(orClauses.join(","));
82	    }
83	  }
84	
85	  return query;
86	}
