88	/**
89	 * Apply visibility logic: assets visible if modified_at >= minDate OR file_created_at >= minDate OR thumbnail_url IS NOT NULL
90	 * Since Supabase JS doesn't support OR across columns easily, we use an RPC-style .or() filter.
91	 */
92	function applyVisibility(query: any, minDate: string) {
93	  return query.or(
94	    `modified_at.gte.${minDate},file_created_at.gte.${minDate},thumbnail_url.not.is.null`
95	  );
96	}
