98	export function useAssets(
99	  filters: AssetFilters,
100	  sortField: SortField,
101	  sortDirection: SortDirection,
102	  page: number,
103	  visibilityDate?: string,
104	  customPageSize?: number,
105	) {
106	  const effectivePageSize = customPageSize ?? PAGE_SIZE;
107	  return useQuery({
108	    queryKey: ["assets", filters, sortField, sortDirection, page, visibilityDate, effectivePageSize],
109	    queryFn: async () => {
110	      const from = page * effectivePageSize;
111	      const to = from + effectivePageSize - 1;
112	      const minDate = visibilityDate ?? "2020-01-01";
113	
114	      let query = supabase
115	        .from("assets")
116	        .select("*", { count: "exact" });
117	
118	      query = applyFilters(query, filters);
119	      query = applyVisibility(query, minDate);
120	      query = query.order(sortField, { ascending: sortDirection === "asc" });
121	      query = query.range(from, to);
122	
123	      const { data, error, count } = await query;
124	      if (error) throw error;
125	
126	      return {
127	        assets: (data ?? []) as Asset[],
128	        totalCount: count ?? 0,
129	        pageSize: effectivePageSize,
130	        page,
131	      };
132	    },
133	    placeholderData: (prev) => prev,
134	  });
