3	 RETURNS jsonb
4	 LANGUAGE plpgsql
5	 SECURITY DEFINER
6	 SET search_path TO 'public'
7	 SET statement_timeout TO '15s'
8	AS $function$
9	DECLARE
10	  result jsonb;
11	  trimmed text;
12	BEGIN
13	  trimmed := lower(trim(query_text));
14	  
15	  -- Allow SELECT and WITH...SELECT (CTEs)
16	  IF NOT (trimmed ~ '^select\s' OR trimmed ~ '^with\s') THEN
17	    RAISE EXCEPTION 'Only SELECT queries are allowed';
18	  END IF;
19	  
20	  IF trimmed ~ '\b(insert|update|delete|drop|alter|create|truncate|grant|revoke|execute)\b' THEN
21	    RAISE EXCEPTION 'Query contains forbidden keywords';
22	  END IF;
23	
24	  EXECUTE format('SELECT jsonb_agg(row_to_json(t)) FROM (%s) t', query_text) INTO result;
25	  
26	  RETURN COALESCE(result, '[]'::jsonb);
27	END;
