37	export function getPathDisplayModes(
38	  relativePath: string,
39	  config: NasConfig,
40	  userSyncRoot?: string | null
41	): PathDisplayModes {
42	  const backslashed = toBackslash(relativePath);
43	  const share = config.NAS_SHARE;
44	
45	  // Detect whether the sync root is a Windows path (e.g. "C:\...") or a
46	  // Mac/Linux POSIX path (e.g. "/Users/..."). Use the appropriate separator
47	  // so the generated path is valid on the user's OS.
48	  const isWindowsSyncRoot = userSyncRoot
49	    ? /^[A-Za-z]:[/\\]/.test(userSyncRoot)
50	    : false;
51	  const remoteRelative = isWindowsSyncRoot ? `${share}\\${backslashed}` : `${share}/${relativePath}`;
52	  const remoteSep = isWindowsSyncRoot ? "\\" : "/";
53	
54	  return {
55	    uncHost: `\\\\${config.NAS_HOST}\\${share}\\${backslashed}`,
56	    uncIp: `\\\\${config.NAS_IP}\\${share}\\${backslashed}`,
57	    remote: userSyncRoot
58	      ? `${userSyncRoot.replace(/[/\\]$/, "")}${remoteSep}${remoteRelative}`
59	      : null,
60	    container: config.NAS_CONTAINER_MOUNT_ROOT
61	      ? `${config.NAS_CONTAINER_MOUNT_ROOT.replace(/\/$/, "")}/${relativePath}`
62	      : null,
63	  };
